/**
 * @suppress
 */
public object FfiConverterTypeGratiaNode: FfiConverter<GratiaNode, Pointer> {

    override fun lower(value: GratiaNode): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): GratiaNode {
        return GratiaNode(value)
    }

    override fun read(buf: ByteBuffer): GratiaNode {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: GratiaNode) = 8UL

    override fun write(value: GratiaNode, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



